import{_ as o,o as a,c as i,a6 as t,bd as n}from"./chunks/framework.zaV2WUSU.js";const p=JSON.parse('{"title":"Tesla-Menu","description":"","frontmatter":{},"headers":[],"relativePath":"homebrew/tesla-menu.md","filePath":"homebrew/tesla-menu.md"}'),l={name:"homebrew/tesla-menu.md"};function s(r,e,c,h,d,u){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="tesla-menu" tabindex="-1">Tesla-Menu <a class="header-anchor" href="#tesla-menu" aria-label="Permalink to “Tesla-Menu”">​</a></h1><p>Tesla-Menu is an overlay menu developed by <a href="https://github.com/WerWolv" target="_blank" rel="noreferrer">WerWolv</a>, Tesla-Menu is comparable to Rosalina menu on the 3DS and its purpose is to be able to load community made overlays for Homebrew apps and sysmodules that can be accessed at any time. Below you can find common use cases for Tesla-Menu. More information can be found on the <a href="https://github.com/WerWolv/Tesla-Menu" target="_blank" rel="noreferrer">Tesla-Menu GitHub</a> repository.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>Dependencies</strong></p><p>Tesla-Menu is dependent on a <a href="./index#terminologies">sysmodule</a> called <code>nx-ovlloader</code>, this sysmodule is responsible for loading <code>ovlmenu.ovl</code> from <code>sd:/switch/.overlays</code>.</p></div><details class="details custom-block"><summary>Common use cases for Tesla-Menu</summary><ul><li>Load community made Tesla-Menu overlays</li><li>Viewing the temperatures/clock speeds of your hardware</li><li>Editing sysmodule configs on the fly (if applicable)</li><li>Editing Homebrew app configs on the fly (if applicable)</li><li>Toggling cheats easily</li><li>Toggling sysmodules</li></ul></details><h2 id="section-i-requirements" tabindex="-1">Section I - Requirements <a class="header-anchor" href="#section-i-requirements" aria-label="Permalink to “Section I - Requirements”">​</a></h2><ul><li>An archive manager like <a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7-Zip</a></li><li>The latest release of <a href="https://github.com/DefenderOfHyrule/Tesla-Menu/releases/tag/v1.2.0" target="_blank" rel="noreferrer">Tesla-Menu</a> (the <code>ovlmenu.ovl</code> file)</li><li>The latest release of <a href="https://github.com/DefenderOfHyrule/nx-ovlloader/releases/tag/v1.2.0" target="_blank" rel="noreferrer">nx-ovlloader</a> (the <code>nx-ovlloader.zip</code> file)</li></ul><h2 id="section-ii-installation" tabindex="-1">Section II - Installation <a class="header-anchor" href="#section-ii-installation" aria-label="Permalink to “Section II - Installation”">​</a></h2><ol><li>Boot into hekate and go to <code>Tools</code> &gt; <code>USB Tools</code> &gt; <code>SD Card</code>, then plug your Switch into your PC via USB.</li><li>Your microSD card should now be accessible on your PC, open it.</li><li>Extract the nx-ovlloader <code>.zip</code> file to a location on your computer. <ul><li>If your archive manager allows for it, you can also simply open the <code>.zip</code> file directly.</li></ul></li><li>Copy the <em>contents</em> of the (extracted) <code>.zip</code> file to the root of your microSD card, then copy <code>ovlmenu.ovl</code> to <code>sd:/switch/.overlays</code>. <ul><li><strong>Optional:</strong> You can verify if you&#39;ve installed Tesla-Menu and nx-ovlloader correctly, you should have a folder called <code>420000000007E51A</code> (nx-ovlloader) in <code>sd:/atmosphere/contents</code> and the <code>ovlmenu.ovl</code> (Tesla-Menu) file in <code>sd:/switch/.overlays</code>.</li></ul></li><li>Boot into CFW.</li></ol><h2 id="section-iii-usage" tabindex="-1">Section III - Usage <a class="header-anchor" href="#section-iii-usage" aria-label="Permalink to “Section III - Usage”">​</a></h2><p>Tesla-Menu can be opened by pressing <code>L</code> + <code>R Stick press (R3)</code> + <code>DPAD down</code>, assuming you use the default configuration.</p><p><img src="'+n+`" alt="tesla"></p><h3 id="changing-the-button-combination" tabindex="-1">Changing the button combination <a class="header-anchor" href="#changing-the-button-combination" aria-label="Permalink to “Changing the button combination”">​</a></h3><p>If you wish to change the default button configuration, see the instructions below:</p><ol><li><p>Navigate to <code>sd:/config</code> on your microSD card.</p></li><li><p>Create a folder named <code>tesla</code> if it doesn&#39;t exist already.</p></li><li><p>Create a file named <code>config.ini</code> in <code>sd:/config/tesla</code>.</p></li><li><p>Paste the following text inside of <code>config.ini</code>:</p><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[tesla]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">key_combo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=L+R+RS</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># A, B, X, Y, LS, RS, L, R, ZL, ZR, PLUS, MINUS, DLEFT, DUP, DRIGHT, DDOWN, SL, SR</span></span></code></pre></div></li><li><p>Change the <code>key_combo</code> value to anything you desire and save the file. The accepted inputs are mentioned on the third line.</p></li></ol><h3 id="commonly-used-tesla-menu-overlays" tabindex="-1">Commonly used Tesla-Menu overlays <a class="header-anchor" href="#commonly-used-tesla-menu-overlays" aria-label="Permalink to “Commonly used Tesla-Menu overlays”">​</a></h3><ul><li><a href="https://github.com/masagrator/Status-Monitor-Overlay" target="_blank" rel="noreferrer">Status-Monitor-Overlay</a></li><li><a href="https://github.com/proferabg/EdiZon-Overlay" target="_blank" rel="noreferrer">EdiZon overlay</a></li><li><a href="https://github.com/nedex/QuickNTP" target="_blank" rel="noreferrer">QuickNTP</a></li><li><a href="https://github.com/XorTroll/emuiibo" target="_blank" rel="noreferrer">Emuiibo</a> (this requires you to also install the Emuiibo sysmodule)</li><li><a href="https://github.com/DefenderOfHyrule/TriPlayer" target="_blank" rel="noreferrer">TriPlayer</a> (this requires you to also install the TriPlayer sysmodule)</li><li><a href="https://github.com/DefenderOfHyrule/ldn_mitm" target="_blank" rel="noreferrer">ldn_mitm</a> (this requires you to also install the ldn_mitm sysmodule)</li><li><a href="https://github.com/averne/Fizeau" target="_blank" rel="noreferrer">Fizeau</a> (this requires you to also install the Fizeau sysmodule)</li></ul><h2 id="section-iv-troubleshooting" tabindex="-1">Section IV - Troubleshooting <a class="header-anchor" href="#section-iv-troubleshooting" aria-label="Permalink to “Section IV - Troubleshooting”">​</a></h2><h3 id="my-switch-crashes-on-boot-after-i-installed-tesla-menu-nx-ovlloader" tabindex="-1">My Switch crashes on boot after I installed Tesla-Menu/nx-ovlloader! <a class="header-anchor" href="#my-switch-crashes-on-boot-after-i-installed-tesla-menu-nx-ovlloader" aria-label="Permalink to “My Switch crashes on boot after I installed Tesla-Menu/nx-ovlloader!”">​</a></h3><p><strong>Cause:</strong> If your Switch crashes with Error code <code>2001-0123 (0xf601)</code> and Title ID <code>420000000007E51A</code>, you didn&#39;t successfully install Tesla-Menu or you aren&#39;t using the latest release of Tesla-Menu, re-follow the installation instructions above.</p><h3 id="my-switch-crashes-when-i-open-an-overlay-via-tesla-menu" tabindex="-1">My Switch crashes when I open an overlay via Tesla-Menu! <a class="header-anchor" href="#my-switch-crashes-when-i-open-an-overlay-via-tesla-menu" aria-label="Permalink to “My Switch crashes when I open an overlay via Tesla-Menu!”">​</a></h3><p><strong>Cause:</strong> If your Switch crashes with Error code <code>2001-0123 (0xf601)</code> and Title ID <code>420000000007E51A</code>, the overlay you&#39;re trying to open/use isn&#39;t up to date. Check its source repository for updates.</p><ul><li>If this overlay doesn&#39;t have an updated release, you may have to look for a forked (updated) release or compile it yourself using the latest <code>libtesla</code> library. The latter is for developers (or advanced users).</li></ul><h3 id="tesla-menu-is-only-showing-while-on-the-main-menu-and-not-in-game" tabindex="-1">Tesla-Menu is only showing while on the main menu and not in-game! <a class="header-anchor" href="#tesla-menu-is-only-showing-while-on-the-main-menu-and-not-in-game" aria-label="Permalink to “Tesla-Menu is only showing while on the main menu and not in-game!”">​</a></h3><p><strong>Cause:</strong> This issue will only happen when the Switch is docked, ensure that you&#39;ve set the &quot;Screen size&quot; in <code>System Settings</code> &gt; <code>TV Output</code> to 100%. Adjust your TV/monitor to fit the entirety of the screen of your Switch using its OSD (On Screen Display) or remote.</p><h3 id="tesla-menu-isn-t-opening-when-i-press-the-correct-button-combination" tabindex="-1">Tesla-Menu isn&#39;t opening when I press the correct button combination! <a class="header-anchor" href="#tesla-menu-isn-t-opening-when-i-press-the-correct-button-combination" aria-label="Permalink to “Tesla-Menu isn&#39;t opening when I press the correct button combination!”">​</a></h3><p>Assuming you&#39;ve followed the installation instructions successfully, this is probably due to the archive bit being set on one or more folders/files on your microSD card. This is usually the result of copying files to a microSD card via a Mac. If you are experiencing this issue, try running the archive bit fixer utility via hekate for all files.</p><p>This can be done by booting into hekate and going to <code>Tools</code> &gt; <code>Arch bit • RCM Touch • Pkg1/2</code> &gt; <code>Fix Archive Bit</code>.</p>`,27)])])}const f=o(l,[["render",s]]);export{p as __pageData,f as default};
